import os, base64

files = {
    'src/App.vue': base64.b64decode('').decode("utf-8"),
    'src/client.ts': base64.b64decode('').decode("utf-8"),
    'src/views/AnalyzeView.vue': base64.b64decode('').decode("utf-8"),
    'src/views/ArchiveView.vue': base64.b64decode('').decode("utf-8"),
}

for path, content in files.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        f.write(content)
    print("Written:", path, "(" + str(len(content)) + " bytes)")
print("All files written successfully!")